 ******************************************************************************/

/** @file*/

#include "internal_nn_math.h"

//// Pooling Functions

void riscv_nn_maxpool_HWC_s8(const q7_t * in_tensor,
                             const uint16_t in_tensor_batch,
                             const uint16_t in_tensor_dim,
                             const uint16_t in_tensor_ch,
                             const uint16_t ker_dim,
                             const uint16_t pad,
                             const uint16_t stride,
                             const uint16_t out_tensor_dim,
                             q7_t * in_tmp_buf,
                             q7_t * out_tensor)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
        {
            long ker_y_start = MAX(0, in_y);
            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
            {
                long ker_x_start = MAX(0, in_x);
                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
                long cur_ch = 0, vl = 0;

                long in_tensor_ch2 = in_tensor_ch;
                while(in_tensor_ch2 > 0)
                {
                    // reset the max values
                    vl = __riscv_vsetvl_e8m8(in_tensor_ch2);
                    vint8m8_t vMax = __riscv_vmv_v_x_i8m8(0x80, vl);

                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                    {
                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                        {
                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                            vint8m8_t vIn = __riscv_vle8_v_i8m8(in_ptr, vl);
                            vMax = __riscv_vmax(vIn, vMax, vl);
                        }
                    }

                    __riscv_vse8(out_tensor, vMax, vl);
                    out_tensor += vl;
                    cur_ch += vl;
                    in_tensor_ch2 -= vl;
                }
            }
        }
        in_tensor += input_len;
    }
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
        {
            long ker_y_start = MAX(0, in_y);
            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
            {
                long ker_x_start = MAX(0, in_x);
                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
                long cur_ch = 0, vl = 0;

                long in_tensor_ch2 = in_tensor_ch;
                while(in_tensor_ch2 > 0)
                {
                    // reset the max values
                    NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VMV_V_X(NDS_VEC_V0, 0x80);

                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                    {
                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                        {
                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                            NDS_VEC_VLE8_V(NDS_VEC_V8, in_ptr);
                            NDS_VEC_VMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
                        }
                    }

                    NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
                    out_tensor += vl;
                    cur_ch += vl;
                    in_tensor_ch2 -= vl;
                }
            }
        }
        in_tensor += input_len;
    }
#elif defined(ENA_DSP_ISA_64)
    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
        {
            long ker_y_start = MAX(0, in_y);
            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
            {
                long ker_x_start = MAX(0, in_x);
                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
                long cur_ch;
                long out_q7x8;

                for(cur_ch = 0; (cur_ch + 8) <= in_tensor_ch; cur_ch += 8)
                {
                    out_q7x8 = 0x8080808080808080;
                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                    {
                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                        {
                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                            long in_q7x8 = *__SIMD64(in_ptr);
                            out_q7x8 = NDS_DSP_SMAX8(in_q7x8, out_q7x8);
                        }
                    }

                    *__SIMD64(out_tensor) = out_q7x8;
                    out_tensor += 8;
                }

                // rest channels
                for (; cur_ch < in_tensor_ch; cur_ch++)
                {
                    int max_val = (int8_t)Q7_MIN;
                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                    {
                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                        {
                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                            max_val = MAX(*in_ptr, max_val);
                        }
                    }
                    *out_tensor++ = max_val;
                }
            }
        }
        in_tensor += input_len;
    }
#elif defined(ENA_DSP_ISA)
    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
        {
            long ker_y_start = MAX(0, in_y);
            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
            {
                long ker_x_start = MAX(0, in_x);
                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
                uint32_t cur_ch;
                long out_q7x4;

                for(cur_ch = 0; (cur_ch + 4) <= in_tensor_ch; cur_ch += 4)
                {
                    out_q7x4 = 0x80808080;
                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                    {
                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                        {
                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                            long in_q7x4 = *__SIMD32(in_ptr);
                            out_q7x4 = NDS_DSP_SMAX8(in_q7x4, out_q7x4);
                        }
                    }
                    *__SIMD32(out_tensor) = out_q7x4;
                    out_tensor += 4;
                }

                // rest channels
                for (; cur_ch < in_tensor_ch; cur_ch++)
                {
                    int max_val = (int8_t)Q7_MIN;
                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                    {
                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                        {
                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                            max_val = MAX(*in_ptr, max_val);
                        }
                    }
                    *out_tensor++ = max_val;
                }
            }
        }
        in_tensor += input_len;
    }
#else
    int16_t i_batch, i_ch_in, i_x, i_y;
    int16_t k_x, k_y;
    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
    const int32_t output_len = out_tensor_dim * out_tensor_dim * in_tensor_ch;

    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
        {
            for (i_y = 0; i_y < out_tensor_dim; i_y++)
            {
