#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
        {
            long ker_y_start = MAX(0, in_y);
            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
            {
                long ker_x_start = MAX(0, in_x);
                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
                long cur_ch = 0, vl = 0;

                if ((ker_y_end > ker_y_start) &&
                    (ker_x_end > ker_x_start))
                {
                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
                    long in_tensor_ch2 = in_tensor_ch;
                    while(in_tensor_ch2 > 0)
                    {
                        // reset the accumulators
                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
                        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);

                        for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                        {
                            for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                            {
                                q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                                NDS_VEC_VLE8_V(NDS_VEC_V8, in_ptr);
                                NDS_VEC_VWADD_WV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
                            }
                        }

                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
                        NDS_VEC_VDIV_VX(NDS_VEC_V0, NDS_VEC_V0, count);
                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
                        NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
                        out_tensor += vl;
                        cur_ch += vl;
                        in_tensor_ch2 -= vl;
                    }
                }
                else
                {
                    // for those outputs in boundary as there is no overlapping
                    // between ifm and kernel
                    nn_set_zero_s8(out_tensor, in_tensor_ch);
                    out_tensor += in_tensor_ch;
                }
            }
        }
        in_tensor += input_len;
    }
#elif defined(ENA_DSP_ISA_64)

