                                sum_q31_0 += in_q7x4.b8.b0;
                                sum_q31_1 += in_q7x4.b8.b1;
                                sum_q31_2 += in_q7x4.b8.b2;
                                sum_q31_3 += in_q7x4.b8.b3;
