/*
 * Minimal vsim profiling harness for riscv_nn_avepool_HWC_s8.
 *
 * Tiny parameters: 1 output pixel, 64 channels (1 strip at e8/M4 VLEN=512).
 * The kernel loop runs ker_dim*ker_dim = 9 iterations (3x3).
 * Total: ~30 vector instructions — vsim finishes in seconds.
 */
#include <stdint.h>
#include "riscv_nn_pooling.h"

/* Small static buffers — no malloc, no file I/O */
static int8_t src[3 * 3 * 64];   /* in_dim=3, ch=64 */
static int8_t dst[1 * 1 * 64];   /* out_dim=1 */
static int8_t tmp[64];

/* Fill src with a simple pattern so loads aren't all zeros */
static void fill_src(void)
{
    for (int i = 0; i < (int)sizeof(src); i++)
        src[i] = (int8_t)(i & 0x7f);
}

int main(void)
{
    /* Enable FP and vector unit */
    __asm__ volatile("csrsi mstatus, 0x1"  ::: "memory");  /* FS */
    __asm__ volatile("csrs  mstatus, %0" :: "r"(1UL << 9));  /* VS */

    fill_src();

    /*
     * Parameters chosen for minimal iteration:
     *   batch=1, in_dim=3, ch=64, ker=3, pad=0, stride=1, out_dim=1
     *   → 1 output pixel, count=9, 1 channel strip
     *   → inner loop: 9x vle8 + vwadd.wv, 1x vdiv, 1x vnsra, 1x vse8
     */
    riscv_nn_avepool_HWC_s8(
        src,            /* in_tensor */
        1,              /* in_tensor_batch */
        3,              /* in_tensor_dim */
        64,             /* in_tensor_ch */
        3,              /* ker_dim */
        0,              /* pad */
        1,              /* stride */
        1,              /* out_tensor_dim */
        tmp,            /* in_tmp_buf */
        dst             /* out_tensor */
    );

    return 0;
}

